// Search pool gabungan: activity files + extra files. Sengaja deduplikasi
// by id untuk safety, walau secara saat ini id antar pool sudah unik.
export const mockSearchableFiles: FileResponse[] = (() => {
  const seen = new Set<string>()
  const combined: FileResponse[] = []
  for (const file of [...mockActivityFiles, ...mockExtraSearchFiles]) {
    if (!seen.has(file.id)) {
      seen.add(file.id)
      combined.push(file)
    }
  }
  return combined
})()
